import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function FarmListPage() {
  const [farms, setFarms] = useState([]);
  const [filter, setFilter] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('http://localhost:10000/api/farms')
      .then(res => setFarms(res.data))
      .catch(err => console.error('❌ Lỗi lấy danh sách:', err));
  }, []);

  const handleDelete = async (id) => {
    if (window.confirm('Bạn có chắc chắn muốn xoá?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`);
        setFarms(farms.filter(f => f._id !== id));
      } catch {
        alert('Xoá thất bại');
      }
    }
  };

  const handleEdit = (id) => {
    alert(`📝 Sửa cơ sở có ID: ${id} (chưa triển khai UI chỉnh sửa)`);
  };

  const handleView = (id) => {
    navigate(`/admin/farms/${id}`);
  };

  const filteredFarms = farms.filter(f =>
    (f.tinh || '').toLowerCase().includes(filter.toLowerCase())
  );

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <input
        type="text"
        placeholder="🔍 Tìm kiếm theo tỉnh..."
        value={filter}
        onChange={e => setFilter(e.target.value)}
        style={{ marginBottom: 12, padding: 8, width: '50%' }}
      />

      <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead style={{ background: '#f0f0f0' }}>
          <tr>
            <th>Tên cơ sở</th>
            <th>Tỉnh</th>
            <th>Huyện</th>
            <th>Xã</th>
            <th>Chủ trại</th>
            <th>SĐT</th>
            <th>🛠️</th>
          </tr>
        </thead>
        <tbody>
          {filteredFarms.map((f, i) => (
            <tr key={i}>
              <td>{f.tenCoSo}</td>
              <td>{f.tinh}</td>
              <td>{f.huyen}</td>
              <td>{f.xa}</td>
              <td>{f.chuTrai}</td>
              <td>{f.soDienThoai}</td>
              <td>
                <button onClick={() => handleView(f._id)}>👁️</button>{' '}
                <button onClick={() => handleEdit(f._id)}>✏️</button>{' '}
                <button onClick={() => handleDelete(f._id)}>🗑️</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default FarmListPage;
